-- SPEX ADDED: BEGIN
CREATE USER encrypt identified by encrypt;

CREATE TABLE encrypt.t_order (order_id INT PRIMARY KEY, user_id INT NOT NULL, status VARCHAR(50) NOT NULL, merchant_id INT, remark VARCHAR(50) NOT NULL, creation_date DATE NOT NULL);
CREATE TABLE encrypt.t_order_item (item_id INT PRIMARY KEY, order_id INT NOT NULL, user_id INT NOT NULL, product_id INT NOT NULL, quantity INT NOT NULL, creation_date DATE NOT NULL);
CREATE TABLE encrypt.t_user (user_id INT PRIMARY KEY, user_name_cipher VARCHAR(50) NOT NULL, user_name_like VARCHAR(50) NOT NULL, user_name_plain VARCHAR(50) NOT NULL, password_plain VARCHAR(50) NOT NULL, password_cipher VARCHAR(50) NOT NULL, email_plain VARCHAR(50) NOT NULL, email_cipher VARCHAR(50) NOT NULL, user_telephone_cipher CHAR(50) NOT NULL, user_telephone_like CHAR(11) NOT NULL, user_telephone_plain CHAR(11) NOT NULL, creation_date DATE NOT NULL);
CREATE TABLE encrypt.t_user_item (item_id INT NOT NULL, user_id INT NOT NULL, status VARCHAR(45) NULL, creation_date DATE, PRIMARY KEY (item_id));
CREATE TABLE encrypt.t_single_table (single_id INT NOT NULL, id INT NOT NULL, status VARCHAR(45) NULL, PRIMARY KEY (single_id));
CREATE TABLE encrypt.t_merchant (merchant_id INT PRIMARY KEY, country_id SMALLINT NOT NULL, merchant_name VARCHAR(50) NOT NULL, business_code_cipher VARCHAR(50) NOT NULL, business_code_like VARCHAR(50) NOT NULL, business_code_plain VARCHAR(50) NOT NULL, merchant_telephone_cipher CHAR(50) NOT NULL, merchant_telephone_like CHAR(11) NOT NULL, merchant_telephone_plain CHAR(11) NOT NULL, creation_date DATE NOT NULL);
CREATE TABLE encrypt.t_merchant_detail (merchant_id INT PRIMARY KEY, business_code_cipher VARCHAR(50) NOT NULL, business_code_like VARCHAR(50) NOT NULL, business_code_plain VARCHAR(50) NOT NULL, merchant_telephone_cipher CHAR(50) NOT NULL, merchant_telephone_like CHAR(11) NOT NULL, merchant_telephone_plain CHAR(11) NOT NULL, status VARCHAR(50) NOT NULL, address VARCHAR(200) NOT NULL, creation_date DATE NOT NULL);
CREATE TABLE encrypt.t_product_extend (extend_id INT PRIMARY KEY, product_id INT NOT NULL, manual_plain CLOB, manual_cipher CLOB);
CREATE TABLE encrypt.t_user_insert (user_id INT PRIMARY KEY, user_name_cipher VARCHAR(100), user_name_plain VARCHAR(50), password VARCHAR(50), creation_date DATE, update_date TIMESTAMP);
CREATE TABLE encrypt.t_user_select (user_id INT PRIMARY KEY, user_name_cipher VARCHAR(100), user_name_plain VARCHAR(50), password VARCHAR(50), creation_date DATE, update_date TIMESTAMP);

CREATE TABLE encrypt.SYS_USR (ID NUMBER NOT NULL CONSTRAINT PK_SYS_USR PRIMARY KEY, USR_NM VARCHAR2(40) NOT NULL, USR_TYP_CD VARCHAR2(30), REG_CHL_CD VARCHAR2(30), OPEN_ID VARCHAR2(32), MP VARCHAR2(30), E_MAIL VARCHAR2(50), QQ VARCHAR2(32), IS_SYS_DEF NUMBER(1), IS_VALID NUMBER(1) DEFAULT 1, IS_DEL NUMBER(1) DEFAULT 0, CRT_TM TIMESTAMP(6) DEFAULT SYSDATE, CRT_USR_ID NUMBER, MDF_TM TIMESTAMP(6) DEFAULT SYSDATE, MDF_USR_ID NUMBER, MP_CIPHER VARCHAR2(500) DEFAULT NULL NOT NULL, E_MAIL_CIPHER VARCHAR2(500) DEFAULT NULL NOT NULL);
CREATE TABLE encrypt.SYS_USR_SYS_R (ID NUMBER NOT NULL CONSTRAINT PK_SYS_USR_SYS_R PRIMARY KEY CONSTRAINT SYS_C0025353 CHECK ("ID" IS NOT NULL), USR_ID NUMBER, USR_NM VARCHAR2(40) NOT NULL CONSTRAINT SYS_C0025354 CHECK ("USR_NM" IS NOT NULL), RL_NM VARCHAR2(100), PWD VARCHAR2(40), SYS_CD VARCHAR2(30), REG_TYP_CD VARCHAR2(30), REG_DT TIMESTAMP(6), IS_VALID NUMBER(1) DEFAULT 1, IS_SYS_DEF NUMBER(1), IS_DEL NUMBER(1) DEFAULT 0, CRT_TM TIMESTAMP(6) DEFAULT SYSDATE, CRT_USR_ID NUMBER, MDF_TM TIMESTAMP(6) DEFAULT SYSDATE, MDF_USR_ID NUMBER, CERT_TYP_CD VARCHAR2(30), CERT_NO VARCHAR2(40), REF_MP VARCHAR2(30), REF_USR_ID NUMBER, REF_USR_BUS_TYP VARCHAR2(30), NICK_NM VARCHAR2(50), LATELY_LOGIN_TM TIMESTAMP(6), NO_TALK_TYP VARCHAR2(30), NO_TALK_TM TIMESTAMP(6), SALT VARCHAR2(30), PWD_CRT_TM TIMESTAMP(6), LOCK_STATE NUMBER(1) DEFAULT 0, IS_LEAVE NUMBER(1) DEFAULT 0, PER_TYPE_CD VARCHAR2(10) DEFAULT 0, MP_STS_CD VARCHAR2(30) DEFAULT 0, RL_NAME_CIPHER VARCHAR2(500) DEFAULT NULL NOT NULL, RL_NAME_FOR_QRY VARCHAR2(500) DEFAULT NULL NOT NULL, CERT_NO_CIPHER VARCHAR2(500) DEFAULT NULL NOT NULL, REF_MP_CIPHER VARCHAR2(500) DEFAULT NULL NOT NULL);
CREATE TABLE encrypt.SYS_USR_EXT_INFO (ID NUMBER NOT NULL CONSTRAINT PK_SYS_USR_EXT_INFO PRIMARY KEY, USR_ID NUMBER, USR_TYP_CD VARCHAR2(30), REG_CHL_CD VARCHAR2(30), CRT_TM TIMESTAMP(6) DEFAULT SYSDATE, CRT_USR_ID NUMBER);

CREATE TABLE encrypt.MC_DATAROLES (ID NUMBER(10) NOT NULL CONSTRAINT PK__MC_DATAR__3213E83F01F4D7EF PRIMARY KEY, CODE VARCHAR2(20 CHAR), TYPE VARCHAR2(200 CHAR), TITLE VARCHAR2(200 CHAR), TITLE1 VARCHAR2(200 CHAR), TITLE2 VARCHAR2(200 CHAR), TITLE3 VARCHAR2(200 CHAR), TITLE4 VARCHAR2(200 CHAR), TITLE5 VARCHAR2(200 CHAR), DISABLED NUMBER(10), REMARK VARCHAR2(200 CHAR), SUBMITBY NUMBER(10), SUBMITTIME DATE, XTYPE NUMBER(10));
CREATE TABLE encrypt.MC_USERDATAROLES (ID NUMBER(10) NOT NULL CONSTRAINT MC_USERDATAROLES PRIMARY KEY, USERID NUMBER(10), DBID NUMBER(10), ROLETYPE VARCHAR2(10), ROLEID NUMBER(10), ORDERBY NUMBER(10), REGTIME DATE, REGBY NUMBER(10), MENUIDS VARCHAR2(4000), SUBMIT1 NUMBER, SUBMITBY1 NUMBER, SUBMITTIME1 DATE, SUBMIT2 NUMBER, SUBMITBY2 NUMBER, SUBMITTIME2 DATE);
CREATE TABLE encrypt.MC_PERMISSIONSCOPE (ID NUMBER(10), USERID NUMBER, XTYPE VARCHAR2(20), TARGETID NUMBER(10), SUBMITBY NUMBER(10), SUBMITTIME DATE);
